function getLang() {
  return localStorage.getItem(I18N_STORAGE_KEY) || 'en';
}

function setLang(lang) {
  localStorage.setItem(I18N_STORAGE_KEY, lang);
  applyTranslations();
}

function t(key, fallback) {
  const lang = getLang();
  return (TRANSLATIONS[lang] && TRANSLATIONS[lang][key]) || fallback || (TRANSLATIONS.en[key] || key);
}

function applyTranslations() {
  const lang = getLang();
  document.documentElement.lang = lang;
  document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';

  document.querySelectorAll('[data-i18n]').forEach((el) => {
    const key = el.getAttribute('data-i18n');
    const val = TRANSLATIONS[lang][key];
    if (val !== undefined) el.textContent = val;
  });

  document.querySelectorAll('[data-i18n-placeholder]').forEach((el) => {
    const key = el.getAttribute('data-i18n-placeholder');
    const val = TRANSLATIONS[lang][key];
    if (val !== undefined) el.placeholder = val;
  });

  document.querySelectorAll('.lang-toggle-btn').forEach((btn) => {
    btn.textContent = lang === 'ar' ? 'English' : 'العربية';
  });

  document.dispatchEvent(new CustomEvent('i18n:applied', { detail: { lang } }));
}

function initLangToggle() {
  document.querySelectorAll('.lang-toggle-btn').forEach((btn) => {
    btn.addEventListener('click', () => setLang(getLang() === 'ar' ? 'en' : 'ar'));
  });
}

document.addEventListener('DOMContentLoaded', () => {
  initLangToggle();
  applyTranslations();
});
